"""Tests for BaseProviderClient error mapping and request helpers."""from __future__ import annotationsimport jsonimport urllib.errorfrom io import BytesIOfrom unittest.mock import MagicMock, patchimport pytestfrom src.modules.llm_providers.module import LLMProvidersConfigfrom src.modules.llm_providers.errors import (    LLMProviderAuthError,    LLMProviderClientError,    LLMProviderRateLimitError,    LLMProviderResponseError,    LLMProviderTransportError,)from src.modules.llm_providers.interfaces.provider_client import BaseProviderClientfrom src.modules.llm_providers.providers.clients import GoogleProvider, MockProviderfrom src.modules.llm_providers.schemas.chat import LLMChatRequest, LLMChatResponsefrom src.modules.llm_providers.schemas.models import LLMModelInfo, LLMModelsRequest, LLMModelsResponseclass _ConcreteProvider(BaseProviderClient):    """Minimal provider used to test shared base behavior."""    BASE_URL = "https://api.example.com"    PROVIDER_CODE = "test"    def _build_headers(self) -> dict[str, str]:        return {"Authorization": "Bearer x"}    def models(self, request: LLMModelsRequest) -> LLMModelsResponse:        return LLMModelsResponse(provider=self.provider_code, models=())    def chat(self, request: LLMChatRequest, *, cache: bool = False) -> LLMChatResponse:        raise NotImplementedError("test provider")    def parse_error_message(self, status_code: int, body_raw: str) -> str | None:        return Nonedef test_map_exception_401_is_auth_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = urllib.error.HTTPError("https://x", 401, "Unauthorized", {}, None)    out = gw._map_exception(err)    assert isinstance(out, LLMProviderAuthError)    assert isinstance(out, LLMProviderClientError)    assert out.cause is errdef test_map_exception_403_is_auth_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = urllib.error.HTTPError("https://x", 403, "Forbidden", {}, None)    out = gw._map_exception(err)    assert isinstance(out, LLMProviderAuthError)    assert isinstance(out, LLMProviderClientError)def test_map_exception_429_is_rate_limit_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = urllib.error.HTTPError("https://x", 429, "Too Many Requests", {}, None)    out = gw._map_exception(err)    assert isinstance(out, LLMProviderRateLimitError)    assert isinstance(out, LLMProviderClientError)def test_map_exception_500_is_response_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = urllib.error.HTTPError("https://x", 500, "Server Error", {}, None)    out = gw._map_exception(err)    assert isinstance(out, LLMProviderResponseError)    assert isinstance(out, LLMProviderClientError)def test_map_exception_urlerror_is_transport_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = urllib.error.URLError("connection refused")    out = gw._map_exception(err)    assert isinstance(out, LLMProviderTransportError)    assert isinstance(out, LLMProviderClientError)def test_map_exception_json_decode_is_response_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = json.JSONDecodeError("Expecting value", "x", 0)    out = gw._map_exception(err)    assert isinstance(out, LLMProviderResponseError)    assert isinstance(out, LLMProviderClientError)def test_send_get_request_success_logs_raw_response():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    body = b'{"data": [{"id": "gpt-4"}]}'    class FakeResponse:        def read(self):            return body        def getcode(self):            return 200        def __enter__(self):            return self        def __exit__(self, *args):            pass    with patch("src.modules.llm_providers.interfaces.provider_client.urllib.request.urlopen", return_value=FakeResponse()):        result = gw._send_get_request("/v1/models")    assert result == {"data": [{"id": "gpt-4"}]}    logger.debug.assert_called()    call_args = logger.debug.call_args    assert "gateway api" in str(call_args)    assert "response" in str(call_args)    assert "test" in str(call_args)    assert "gpt-4" in str(call_args)def test_send_get_request_http_error_logs_and_raises_gateway_error():    config = LLMProvidersConfig()    logger = MagicMock()    gw = _ConcreteProvider(config, logger)    err = urllib.error.HTTPError("https://x", 401, "Unauthorized", {}, BytesIO(b"invalid key"))    with patch("src.modules.llm_providers.interfaces.provider_client.urllib.request.urlopen", side_effect=err):        with pytest.raises(LLMProviderAuthError) as exc_info:            gw._send_get_request("/v1/models")    assert exc_info.value.cause is err    logger.debug.assert_called()    call_args = logger.debug.call_args    assert "gateway api" in str(call_args)    assert "error" in str(call_args)def test_mock_gateway_models_returns_models_response():    config = LLMProvidersConfig()    logger = MagicMock()    gw = MockProvider(config, logger)    response = gw.models(LLMModelsRequest(provider="mock"))    assert response.provider == "mock"    assert len(response.models) == 1    assert response.models[0].provider == "mock"    assert response.models[0].model == "default"    assert response.models[0].created == 0def test_google_provider_models_parses_google_response():    config = LLMProvidersConfig(        google_provider_enabled=True,        google_api_key="secret",    )    logger = MagicMock()    provider = GoogleProvider(config, logger)    body = (        b'{"models": ['        b'{"name": "models/gemini-1.5-pro", "supportedGenerationMethods": ["generateContent"]},'        b'{"name": "models/text-embedding-004", "supportedGenerationMethods": ["embedContent"]}'        b']}'    )    class FakeResponse:        def read(self):            return body        def getcode(self):            return 200        def __enter__(self):            return self        def __exit__(self, *args):            pass    with patch("src.modules.llm_providers.interfaces.provider_client.urllib.request.urlopen", return_value=FakeResponse()):        response = provider.models(LLMModelsRequest(provider="google"))    assert response.provider == "google"    assert len(response.models) == 1    assert response.models[0].provider == "google"    assert response.models[0].model == "gemini-1.5-pro"